module RefModule(
    input clk,
    input reset,
    input start,
    input [7:0] data1,
    input [7:0] data2,
    output reg [7:0] result,
    output reg done
);
    reg unused_anding;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            result <= 8'd0;
            done <= 1'b0;
            unused_anding <= 1'b0;
        end else if (start && !unused_anding) begin
            unused_anding <= 1'b1;
            done <= 1'b0;
        end else if (unused_anding) begin
            result <= data1 & data2;
            unused_anding <= 1'b0;
            done <= 1'b1;
        end
    end
endmodule
